import { useState, useEffect, useCallback } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import BootstrapTable from 'react-bootstrap-table-next';

import constFlaskURL from '../consts/constFlaskURL'

import '../App.css';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'


const columns = [
    {
        dataField: 'id',
        text: 'ID'
    }, 
    {
        dataField: 'type_crossroad',
        text: 'Тип перекрестка'
    }
];


function TypeCrossroad() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(''); //исправить
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };


    const transformDataForTable = (data) => {
        if (!Array.isArray(data) || data.length === 0) 
        {
            return [];
        }

        return data.map(
            (item, index) => (
                {
                    id: index + 1,
                    ...item
                }
            )
        );
    };

    const fetchTableData = useCallback(async () => {
        setLoading(true);
        // setError('');

        try 
        {
            const response = await constFlaskURL.get('/type_crossroads');

            if (response.status === 200) 
            {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } 
        catch (err) 
        {
            console.log(err);
            // let errorMessage = '';

            // if (err.response) {
            //     errorMessage = err.response.data.message || `Ошибка ${err.response.status}`;

            //     if (err.response.status === 401) 
            //     {
            //         setTimeout(() => navigate('/login'), 1500);
            //     }
            // } 
            // else if (err.request) 
            // {
            //     errorMessage = 'Нет ответа от сервера';
            // } 
            // else 
            // {
            //     errorMessage = 'Ошибка при отправке запроса';
            // }

            // setError(errorMessage);
        } 
        finally 
        {
            setLoading(false);
        }
    }, [navigate]);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    const transformedData = transformDataForTable(tableData);

    return (
        <div> 
            {loading ? 
            (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : transformedData.length > 0 ? 
            (
                <div>
                    <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                        <div className='container-fluid py-2'>
                            <Link className='navbar-brand fs-3 fw-bold' to='/main'>roads_admin</Link>
                            <div class="btn-group">
                                <button type="button" class="btn btn-info">Пользователь</button>
                                <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                                    <span class="visually-hidden">Переключатель выпадающего списка</span>
                                </button>
                                <ul class="dropdown-menu">
                                    <li>
                                        <a class="dropdown-item">
                                            <button
                                                onClick={handleLogout} 
                                                className='dropdown-item'
                                                disabled={loading}
                                            >
                                            {loading ? (
                                                <>
                                                    <span className='spinner'></span>
                                                    Выход...
                                                </>
                                                ) : 'Выйти'}
                                            </button>
                                        </a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                        <div className='container-fluid bg-dark py-2'>
                            <div className='navbar-nav flex-row'>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/main' end> Главная </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads' end> Дороги </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/sings' end> Дорожные знаки </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads/sings' end> Знаки на дорогах </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/type_crossroad' end> Типы перекрестков </NavLink>
                            </div>
                        </div>
                    </nav>
                    <div className='container'>
                        <p className="Table-header"><h1>Типы перекрестков.</h1></p>

                        <div>
                        <BootstrapTable
                            keyField="id"
                            data={tableData[0]?.items}
                            columns={columns}
                        />
                        </div>
                    </div>
                </div>
            ) : (
                <p className="no-data">Нет данных для отображения</p>
            )}
        </div>
    );
}

export default TypeCrossroad;
